
.files {
  height: calc(100% - 76px);
  border-top: 1px solid #d8d8d8;
  overflow: scroll;
  display: flex;

  .fileList {
    width: 224px;
    padding-top: 8px;
    border-right: 1px solid #d8d8d8;
    overflow: scroll;

    .txt {
      width: 216px;
      height: 36px;
      line-height: 36px;
      display: flex;
      align-items: center;
      border-radius: 4px;
      cursor: pointer;
      margin: 0 auto;
      img {
        width: 24px;
        height: 24px;
        border: 0.6px solid #e0e0e0;
        border-radius: 4px;
        margin: 0 8px;
      }
      span {
        overflow: hidden;
        text-overflow: ellipsis;
        white-space: nowrap;
      }
      &:hover {
        background: rgba(26, 19, 15, 0.06);
      }
      &.isActive {
        background: rgba(26, 19, 15, 0.06);
      }
    }
  }
  .fileDetails {
    width: calc(100% - 224px);
    overflow: scroll;
    .header {
      height: 44px;
      line-height: 44px;
      border-bottom: 1px solid #d8d8d8;
      display: flex;
      align-items: center;
      justify-content: space-between;
      .desc {
        display: flex;
        align-items: center;
        color: #857c77;
        .arrowLeft {
          width: 7px;
          height: 13px;
          margin: 0 12px 0 20px;
        }
        .name {
          max-width: 340px;
          display: inline-block;
          overflow: hidden;
          white-space: nowrap;
          text-overflow: ellipsis;
        }
      }

      .actions {
        height: 32px;
        padding: 0 8px;
        display: inline-block;
        line-height: 32px;
        text-align: center;
        background: rgba(26, 19, 15, 0.06);
        border-radius: 4px;
        margin-right: 16px;
        cursor: pointer;
        &:hover {
          background: rgba(26, 19, 15, 0.1);
        }
      }
    }
    .logo {
      text-align: center;
      margin: 20px 0;
      img {
        width: 100px;
        height: 100px;
      }
    }
    .li {
      height: 38px;
      line-height: 38px;
      display: flex;
      align-items: center;
      justify-content: space-between;
      padding: 0 16px;
      border-bottom: 1px solid #d8d8d8;
      color: #857c77;
    }
  }
}
