@import '~src/css/quasar.variables.scss', 'quasar/src/css/variables.sass';

.list {
  height: calc(100% - 48px);
  border-top: 1px solid $separator-color;
  overflow: scroll;
  scrollbar-width: none;

  .category {
    width: calc(100% - 32px);
    margin: 0 16px;
    height: 42px;
    line-height: 42px;
    padding-left: 16px;
    font-weight: 500;
    font-size: 14px;
    color: #857c77;
  }
  .item {
    width: calc(100% - 32px);
    height: 40px;
    line-height: 40px;
    border-radius: 12px;
    margin: 0 16px 4px;
    display: flex;
    align-items: center;
    justify-content: space-between;
    cursor: pointer;
    position: relative;
    .txt {
      display: flex;
      align-items: center;
      img {
        width: 24px;
        height: 24px;
        border-radius: 4px;
        margin: 0 8px;
      }
    }
    .icon {
      margin-right: 16px;
      width: 24px;
      height: 24px;
      border-radius: 4px;
      display: flex;
      align-items: center;
      justify-content: center;
      &:hover {
        background: rgba(133, 124, 119, 0.2);
      }
    }

    &:hover {
      background: $background-hover;
    }
    &.isActive {
      background: $background-selected;
    }
  }
}
