@import '~src/css/quasar.variables.scss', 'quasar/src/css/variables.sass';

.dialog_card {
  width: 100%;
  height: 556px;
  border-radius: 12px;

  .content {
    height: 492px;
  }

  .searchCard {
    width: calc(100% - 32px);
    height: 40px;
    line-height: 40px;
    border-radius: 12px !important;
    margin: 0 auto 8px;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 16px;
    position: relative;

    .icon {
      width: 18px;
      height: 18px;
    }

    .btn {
      padding: 8px 12px;
      font-weight: 400;
      font-size: 14px;
      line-height: 14px;
      color: #1a130f;
      background: rgba(26, 19, 15, 0.06);
      border-radius: 4px;
      cursor: pointer;

      &:hover {
        background: rgba(26, 19, 15, 0.1);
      }
    }

    .input {
      flex: 1;
      height: 100%;
      border: none;
      outline: none;
      margin: 0 12px;
      font-weight: 400;
      font-size: 16px;
      line-height: 20px;
      color: #857c77;
      background: rgba(255, 255, 255, 0);

      &::placeholder {
        color: #bdbdbd;
      }
    }

    .appIcon {
      height: 32px;
      display: flex;
      align-items: center;
      justify-content: space-around;
      background: $background-4;
      border-radius: 4px;
      padding: 8px 12px;
      margin-left: 18px;
    }
  }
}
