
.animationClass {
  top: 0 !important;
  left: calc(100vw + 108px) !important;
  transition: all 0.3s;

  .content-container {
    width: calc(100vw - 108px) !important;
    height: 100vh !important;
    transition: all 0.3s;
  }
}

.animationClass2 {
  top: 0 !important;
  transition: all 0.3s;

  .content-container {
    height: 100vh !important;
    transition: all 0.3s;
  }
}
