
.description_box {
  position: absolute;
  bottom: 122px;
  right: 165px;
  .description_weather {
    height: 72px;
    display: flex;
    .description_time {
      font-size: 70px;
      font-family: Roboto-Bold, Roboto;
      font-weight: bold;
      color: #ffffff;
      line-height: 72px;
      text-shadow: 0px 2px 6px rgba(0, 0, 0, 0.16);
    }
    .description_daily {
      display: flex;
      padding-top: 14px;
      margin-left: 14px;
      p {
        margin: 0;
      }
      .description_singapore {
        .description_week {
          font-size: 20px;
          font-family: Roboto-Bold, Roboto;
          font-weight: bold;
          color: #ffffff;
          text-shadow: 0px 2px 6px rgba(0, 0, 0, 0.16);
        }
        .description_day {
          font-size: 12px;
          font-family: Roboto-Regular, Roboto;
          font-weight: 400;
          color: #ffffff;
          text-shadow: 0px 2px 6px rgba(0, 0, 0, 0.16);
        }
      }
    }
  }
  .description_thickness {
    display: flex;
    margin-top: 15px;
    justify-content: space-between;
    .q-circular-progress__track {
      color: rgba(255, 255, 255, 0.46) !important;
    }
    .description_track {
      display: flex;
      opacity: 0.8;
      p {
        margin: 0px;
      }
      .description_track_txt {
        font-size: 12px;
        font-family: Roboto-Regular, Roboto;
        font-weight: 400;
        color: #ffffff;
        line-height: 12px;
        text-shadow: 0px 2px 6px rgba(0, 0, 0, 0.16);
        margin-left: 8px;
      }
    }
  }
}
