@import '~src/css/quasar.variables.scss', 'quasar/src/css/variables.sass';

.drag-enter {
  border: 1px dashed white;
}

.drag-start {
  opacity: 0;
}

.dialog_box {
  .dialog_card {
    width: 426px;
    min-height: 155px;
    border-radius: 8px;
  }
  .launch_dialog_span {
    width: 300px;
  }
  .launch_dialog_btn {
    position: absolute;
    bottom: 0px;
    right: 0px;
  }
  .launch_pad_dialog {
    width: 70px;
    height: 70px;
    border-radius: 16px;
  }
}
.pad_carousel {
  background: transparent !important;
  box-shadow: none !important;
  height: 90% !important;
  overflow: hidden !important;
}

.dragMask {
  width: 140%;
  height: 120%;
  transform: translate(-13%, -10%);
  position: absolute;
  top: 0;
  left: 0;
  z-index: 2;
  overflow: hidden;
  cursor: pointer;
}

.column_none {
  overflow: hidden !important;
}
.column_launch_pad_apps {
  .launch_pad_apps_name {
    width: 140%;
    transform: translateX(-15%);
    text-align: center;
    font-size: 14px;
    font-family: Roboto-Medium, Roboto;
    font-weight: 500;
    color: #ffffff;
    overflow: hidden;
    white-space: nowrap;
    text-overflow: ellipsis;
    margin-top: 12px;
    .app_state {
      display: inline-block;
      width: 8px;
      height: 8px;
      border-radius: 4px;
      &.suspend_color {
        background-color: $warning;
      }
      &.crash_color {
        background-color: $negative;
      }
      &.running_color {
        background-color: $positive;
      }
    }
  }
  .delete_launch {
    width: 20px;
    height: 20px;
    background-image: url('./../assets/delete_app_icon.svg');
    background-repeat: no-repeat;
    background-position: center;
    background-size: contain;
    position: absolute;
    top: -5px;
    left: -5px;
    z-index: 99;
    cursor: pointer;
  }
  .install_loading_status {
    position: absolute;
    top: 0px;
    left: 0px;
    z-index: 99;
    background-image: url('./../assets/installing.svg');
    background-position: center;
    background-size: 100% 100%;
    background-repeat: no-repeat;
    display: flex;
    align-items: center;
    justify-content: center;
    svg {
      transform: rotate(-90deg);
      border-radius: 50%;
      height: 40%;
    }
    circle {
      fill: rgba(0, 0, 0, 0.5);
      stroke: rgba(255, 255, 255, 1);
      stroke-width: 32;
      stroke-dasharray: 0 100;
      animation: fillup 5s linear infinite;
    }
    @keyframes fillup {
      to {
        stroke-dasharray: 158 158;
        opacity: 0;
      }
    }
  }
}
.launch_pad_page {
  width: 100%;
  height: 100%;
  z-index: 9;
  position: relative;
  top: 0px;
  left: 0px;
  .launch_page_mask {
    position: absolute;
    left: 0;
    height: 0;
    z-index: -1;
    width: 100%;
    height: 100%;
    background: rgba(0, 0, 0, 0.5);
    backdrop-filter: blur(10px);
  }
  .launch_search {
    width: 240px;
    height: 32px !important;
    line-height: 32px !important;
    border-radius: 8px;
    position: relative;
    font-size: 12px !important;
    padding-left: 8px;

    border: 1px solid rgba(255, 255, 255, 0.2);
    background: rgba(246, 246, 246, 0.1);
    box-shadow: 0px 0px 40px 0px rgba(0, 0, 0, 0.2),
      0px 0px 2px 0px rgba(0, 0, 0, 0.4);
    .search_icon {
      margin-bottom: 8px;
      color: rgba(255, 255, 255, 0.8);
    }
    .search_clean {
      margin-bottom: 10px;
      color: rgba(255, 255, 255, 0.8);
    }
    .search_input {
      position: absolute;
      top: 0px;
      left: 24px;
      color: rgba(255, 255, 255, 0.8);
      width: 100%;
      height: 32px;
      margin-bottom: 2px;
      font-size: 14px;
      font-weight: 500;
      z-index: -999;
    }
  }
}
.launch_pad_box {
  width: calc(100% - 108px);
  height: 100%;
  box-shadow: none;
  margin-left: 108px;
  padding-top: 36px;
  overflow: hidden;
  .launch_pad_search {
    width: 100%;
    height: 44px;
    display: flex;
    justify-content: center;
    align-items: center;
  }

  .data_empty {
    color: #e5e5e5;
    font-size: 20px;
    margin-top: calc(50% - 180px);
    text-align: center;
  }
}

.carousel_dot {
  display: inline-block;
  width: 8px;
  height: 8px;
  background-color: rgba(255, 255, 255, 0.3);
  border-radius: 4px;
  cursor: pointer;
  &.active {
    background-color: rgba(255, 255, 255, 1);
  }
}
.in_center_page {
  -webkit-animation: puff_in_center_page 0.6s;
  animation: puff_in_center_page 0.6s;
}
@-webkit-keyframes puff_in_center_page {
  0% {
    opacity: 0;
  }
  100% {
    opacity: 1;
  }
}
@keyframes puff_in_center_page {
  0% {
    opacity: 0;
  }
  100% {
    opacity: 1;
  }
}
.in-center {
  -webkit-animation: puff-in-center 0.6s;
  animation: puff-in-center 0.6s;
}

@-webkit-keyframes puff-in-center {
  0% {
    -webkit-transform: scale(0);
    transform: scale(0);
    opacity: 0;
  }
  50% {
    -webkit-transform: scale(1.03);
    transform: scale(1.03);
    opacity: 0;
  }
  60% {
    -webkit-transform: scale(1.02);
    transform: scale(1.02);
    opacity: 0.6;
  }
  100% {
    -webkit-transform: scale(1);
    transform: scale(1);
    opacity: 1;
  }
}
@keyframes puff-in-center {
  0% {
    -webkit-transform: scale(0);
    transform: scale(0);
    opacity: 0;
  }
  50% {
    -webkit-transform: scale(1.03);
    transform: scale(1.03);
    opacity: 0;
  }
  60% {
    -webkit-transform: scale(1.02);
    transform: scale(1.02);
    opacity: 0.6;
  }

  100% {
    -webkit-transform: scale(1);
    transform: scale(1);
    opacity: 1;
  }
}
:global(.q-field--standard .q-field__control:before) {
  border: none;
}
:global(.q-field--standard .q-field__control:after) {
  height: 0px;
}
:global(.q-field__native) {
  font-family: Roboto-Medium, Roboto;
  font-weight: 500;
  // color: #ffffff;
}
:global(.q-field__marginal) {
  height: 100%;
  padding-right: 4px !important;
}
.q-field__marginal :global(.q-field__control) {
  height: 44px;
}
.ghost {
  opacity: 0 !important;
}
.vibrate-1 {
  -webkit-animation: vibrate-1 0.3s linear infinite both;
  animation: vibrate-1 0.3s linear infinite both;
}

@-webkit-keyframes vibrate-1 {
  0% {
    transform: rotate(4deg);
    -webkit-transform: rotate(4deg);
  }

  50% {
    transform: rotate(-3deg);
    -webkit-transform: rotate(-3deg);
  }
  100% {
    transform: rotate(4deg);
    -webkit-transform: rotate(4deg);
  }
}
@keyframes vibrate-1 {
  0% {
    transform: rotate(4deg);
    -webkit-transform: rotate(4deg);
  }

  50% {
    transform: rotate(-3deg);
    -webkit-transform: rotate(-3deg);
  }
  100% {
    transform: rotate(4deg);
    -webkit-transform: rotate(4deg);
  }
}

.uninstallAni {
  display: inline-block;
  animation: scaleFadeOut 0.5s forwards ease-in-out;
}

@keyframes scaleFadeOut {
  0% {
    transform: scale(1);
    opacity: 1;
  }
  20% {
    transform: scale(1.2);
    opacity: 1;
  }
  100% {
    transform: scale(0);
    opacity: 0;
  }
}

:global(.q-carousel__navigation-icon) {
  font-size: 5px !important;
}
