
.drag-enter {
  border: 1px dashed white;
}

.drag-start {
  opacity: 0;
}

.dialog_box {
  .dialog_card {
    width: 426px;
    min-height: 155px;
    border-radius: 8px;
  }
  .launch_dialog_span {
    width: 300px;
  }
  .launch_dialog_btn {
    position: absolute;
    bottom: 0px;
    right: 0px;
  }
  .launch_pad_dialog {
    width: 70px;
    height: 70px;
    border-radius: 16px;
  }
}
.q_vackgr_carousel {
  background: transparent !important;
  box-shadow: none !important;
  height: 90% !important;
  overflow: hidden !important;
}

.dragMask {
  width: 140%;
  height: 120%;
  transform: translate(-14%, -10%);
  position: absolute;
  top: 0;
  left: 0;
  z-index: 2;
  border-radius: 10px;
  overflow: hidden;
  cursor: pointer;
}

.column_none {
  overflow: hidden !important;
}
.column_launchpadapps {
  display: grid;
  grid-template-rows: 80px 80px 80px 80px;
  grid-template-columns: repeat(4, 25%);
  grid-row-gap: 30px;
  padding-top: 60px;
  .pad-img {
    width: 58px;
    height: 58px;
    -webkit-touch-callout: none;
    -webkit-user-select: none;
    -webkit-user-drag: none;
  }
  .launchpadapps_name {
    width: 100%;
    text-align: center;
    font-family: Roboto-Medium, Roboto;
    font-size: 12px;
    font-style: normal;
    font-weight: 400;
    line-height: 16px;
    color: #ffffff;
    overflow: hidden;
    white-space: nowrap;
    text-overflow: ellipsis;
    margin-top: 12px;
  }
  .delete_launch {
    width: 36px;
    height: 36px;
    background-image: url('./../../assets/delete_app_icon.svg');
    background-repeat: no-repeat;
    background-position: center;
    background-size: 60% 60%;
    position: absolute;
    top: -14px;
    left: 7px;
    z-index: 99;
    cursor: pointer;
  }
  .install_loading_status {
    position: absolute;
    top: 0px;
    left: 0px;
    z-index: 99;
    background-image: url('./../../assets/installing.svg');
    background-position: center;
    background-size: 100% 100%;
    background-repeat: no-repeat;
    border-radius: 16px;
    display: flex;
    align-items: center;
    justify-content: center;
    svg {
      transform: rotate(-90deg);
      border-radius: 50%;
      height: 40%;
    }
    circle {
      fill: rgba(0, 0, 0, 0.5);
      stroke: rgba(255, 255, 255, 1);
      stroke-width: 32;
      stroke-dasharray: 0 100;
      animation: fillup 5s linear infinite;
    }
    @keyframes fillup {
      to {
        stroke-dasharray: 158 158;
        opacity: 0;
      }
    }
  }
}
.Launch_pad_page {
  width: 100%;
  height: 100%;
  background: rgba(0, 0, 0, 0.5);
  backdrop-filter: blur(10px);
  z-index: 9;
  position: absolute;
  top: 0px;
  left: 0px;
  touch-action: none;
}
.launch_pad_box {
  width: 100%;
  height: 100%;
  box-shadow: none;
  overflow: hidden;
  .launch_pad_APPs {
    width: 100%;
    display: flex;
    flex-wrap: wrap;
    .launch_pad_Dragg {
      width: 100%;
      display: flex;
      flex-wrap: wrap;
      align-content: flex-start;
      .launch_pad_drag {
        width: calc(100% / 7);
        margin-bottom: 48px;
        cursor: pointer;
      }
    }

    .launch_myapps_box {
      width: 70%;
      .contain_img {
        display: flex;
        justify-content: center;
        align-items: center;

        .animation_delete {
          width: 70px;
          position: relative;
        }
      }

      .launch_pad_myapps_logo {
        display: flex;
        width: 70px;
        height: 70px;
        background: #ffffff;
        box-shadow: 0px 2px 12px 0px rgba(0, 0, 0, 0.2);
        border-radius: 16px;
      }
      .launch_myapps_text {
        width: 100%;
        font-size: 14px;
        font-family: Roboto-Medium, Roboto;
        font-weight: 500;
        color: #ffffff;
        margin-top: 12px;
        text-align: center;
      }
    }
  }

  .noresult {
    color: #e5e5e5;
    font-size: 20px;
    margin-top: calc(50% - 180px);
    text-align: center;
  }

  .close {
    position: absolute;
    top: calc(100vh - 188px);
    left: 0;
    right: 0;
    margin: auto;
    width: 56px;
    height: 56px;
    border-radius: 28px;
    background-color: rgba(255, 255, 255, 0.9);
  }
}
.in-center-page {
  -webkit-animation: puff-in-center-page 0.6s;
  animation: puff-in-center-page 0.6s;
}
@-webkit-keyframes puff-in-center-page {
  0% {
    opacity: 0;
  }
  100% {
    opacity: 1;
  }
}
@keyframes puff-in-center-page {
  0% {
    opacity: 0;
  }
  100% {
    opacity: 1;
  }
}
.in-center {
  -webkit-animation: puff-in-center 0.6s;
  animation: puff-in-center 0.6s;
}

@-webkit-keyframes puff-in-center {
  0% {
    -webkit-transform: scale(0);
    transform: scale(0);
    opacity: 0;
  }
  50% {
    -webkit-transform: scale(1.03);
    transform: scale(1.03);
    opacity: 0;
  }
  60% {
    -webkit-transform: scale(1.02);
    transform: scale(1.02);
    opacity: 0.6;
  }
  100% {
    -webkit-transform: scale(1);
    transform: scale(1);
    opacity: 1;
  }
}
@keyframes puff-in-center {
  0% {
    -webkit-transform: scale(0);
    transform: scale(0);
    opacity: 0;
  }
  50% {
    -webkit-transform: scale(1.03);
    transform: scale(1.03);
    opacity: 0;
  }
  60% {
    -webkit-transform: scale(1.02);
    transform: scale(1.02);
    opacity: 0.6;
  }

  100% {
    -webkit-transform: scale(1);
    transform: scale(1);
    opacity: 1;
  }
}
:global(.q-field--standard .q-field__control:before) {
  border: none;
}
:global(.q-field--standard .q-field__control:after) {
  height: 0px;
}
:global(.q-field__native) {
  font-family: Roboto-Medium, Roboto;
  font-weight: 500;
  // color: #ffffff;
}
:global(.q-field__marginal) {
  height: 100%;
  padding-right: 4px !important;
}
.q-field__marginal :global(.q-field__control) {
  height: 44px;
}
.ghost {
  opacity: 0 !important;
}
.vibrate-1 {
  -webkit-animation: vibrate-1 0.3s linear infinite both;
  animation: vibrate-1 0.3s linear infinite both;
}

@-webkit-keyframes vibrate-1 {
  0% {
    transform: rotate(6deg);
    -webkit-transform: rotate(6deg);
  }

  50% {
    transform: rotate(-5deg);
    -webkit-transform: rotate(-5deg);
  }
  100% {
    transform: rotate(6deg);
    -webkit-transform: rotate(6deg);
  }
}
@keyframes vibrate-1 {
  0% {
    transform: rotate(6deg);
    -webkit-transform: rotate(6deg);
  }

  50% {
    transform: rotate(-5deg);
    -webkit-transform: rotate(-5deg);
  }
  100% {
    transform: rotate(6deg);
    -webkit-transform: rotate(6deg);
  }
}

:global(.q-carousel__navigation-icon) {
  font-size: 5px !important;
}

.carousel_dot {
  display: inline-block;
  width: 8px;
  height: 8px;
  background-color: rgba(255, 255, 255, 0.3);
  border-radius: 4px;
  cursor: pointer;
  &.active {
    background-color: rgba(255, 255, 255, 1);
  }
}
