@import '~src/css/quasar.variables.scss', 'quasar/src/css/variables.sass';

.card-dialog {
  .card-continer {
    width: 400px;
    border-radius: 12px;
    padding: 20px;

    .dialog-header {
      width: 100%;
      height: 36px;
      line-height: 36px;
      font-size: 16px;
      font-weight: 500;
      line-height: 24px;
      text-align: left;
      margin-bottom: 12px;
    }

    .dialog-desc {
      .img {
        width: 32px;
        height: 32px;
        border-radius: 8px;
      }
      .message {
        max-width: calc(100% - 45px);
        font-size: 12px;
        line-height: 16px;
      }
    }

    .confirm {
      width: 68px;
      text-align: center;
      margin-top: 40px;
      padding: 8px 12px;
      border-radius: 8px;
      font-size: 12px;
      line-height: 16px;
      float: right;
      cursor: pointer;
      &:hover {
        opacity: 0.8;
      }
    }

    .cancel {
      width: 68px;
      text-align: center;
      margin-top: 40px;
      padding: 8px 0;
      border-radius: 8px;
      font-size: 12px;
      line-height: 16px;
      float: right;
      cursor: pointer;
      border: 1px solid $btn-stroke;
      &:hover {
        opacity: 0.8;
      }
    }

    .confirm-mobile {
      width: 46%;
      height: 48px;
      line-height: 48px;
      margin-top: 12px;
      text-align: center;
      border-radius: 8px;
      font-size: 16px;
      float: right;
      cursor: pointer;
      &:hover {
        opacity: 0.8;
      }
    }

    .cancel-mobile {
      width: 46%;
      height: 48px;
      line-height: 48px;
      margin-top: 12px;
      text-align: center;
      border-radius: 8px;
      font-size: 16px;
      float: right;
      cursor: pointer;
      border: 1px solid $btn-stroke;
      &:hover {
        opacity: 0.8;
      }
    }
  }
}
