
.description_box {
  width: calc(100vw - 100px);
  position: absolute;
  top: 116px;
  left: 0;
  right: 0;
  margin: auto;
  .description_weather {
    width: 100%;
    height: 72px;
    display: flex;
    align-items: center;
    font-style: normal;
    font-weight: 700;
    line-height: normal;
    color: #ffffff;
    display: flex;
    align-items: center;
    justify-content: space-around;
    .date {
      display: inline-block;
      height: 100%;
      font-size: 0.64rem;
      font-weight: 700;
      span {
        color: rgba(255, 255, 255, 0.5);
      }
    }
    .year_week {
      display: inline-block;
      height: 100%;
      display: flex;
      align-items: start;
      justify-content: center;
      flex-direction: column;
      .year {
        font-size: 0.18rem;
        line-height: 0.22rem;
      }
      .week {
        font-size: 0.18rem;
        font-weight: 500;
        line-height: 0.22rem;
      }
    }
  }
  .description_thickness {
    width: 100%;
    height: 40px;
    display: flex;
    margin-top: 15px;
    justify-content: space-between;
    .q-circular-progress__track {
      color: rgba(255, 255, 255, 0.46) !important;
    }
    .description_track {
      display: flex;
      opacity: 0.8;
      p {
        margin: 0px;
      }
      .description_track_txt {
        height: 32px;
        font-size: 12px;
        font-family: Roboto-Regular, Roboto;
        font-weight: 400;
        color: #ffffff;
        line-height: 12px;
        text-shadow: 0px 2px 6px rgba(0, 0, 0, 0.16);
        margin-left: 8px;
        display: flex;
        align-items: start;
        justify-content: space-around;
        flex-direction: column;
      }
    }
  }
}
