
.desktop-box {
  .desktop-app-box {
    width: 100%;
    display: flex;
    align-items: center;
    justify-content: space-around;
    position: fixed;
    bottom: 76px;
    left: 0;
    right: 0;
    margin: auto;
    z-index: 9;

    .launch-app {
      .app-img {
        width: 0.52rem;
        height: 0.52rem;
        border-radius: 0.14rem;
        -webkit-touch-callout: none;
        -webkit-user-select: none;
        -webkit-user-drag: none;
        overflow: hidden;
        position: relative;
        img {
          width: 100%;
          height: 100%;
        }
        .overlay {
          width: 100%;
          height: 100%;
          position: absolute;
          top: 0;
          left: 0;
          right: 0;
          bottom: 0;
          background: transparent;
        }
      }
      .app-name {
        width: 100%;
        height: 0.16rem;
        border-radius: 0.14rem;
        font-size: 12px;
        font-style: normal;
        font-weight: 400;
        line-height: 16px;
        color: #fff;
        text-align: center;
      }
    }
  }
}

.dockAni {
  animation: DockAni 0.5s ease-in-out;
}

@keyframes DockAni {
  from {
    bottom: 66px;
    opacity: 0;
  }
  to {
    bottom: 76px;
    opacity: 1;
  }
}
