
.search-footer {
  width: 100%;
  height: 48px;
  display: flex;
  align-items: center;
  border-top: 1px solid rgba(0, 0, 0, 0.1);
  span {
    color: #adadad;
  }

  .esc {
    width: 24px;
    height: 24px;
    border-radius: 4px;
    display: flex;
    align-items: center;
    justify-content: center;
    img {
      width: 16px;
      height: 16px;
    }
  }

  .separator {
    width: 1px;
    height: 20px;
    border-right: 1px solid rgba(0, 0, 0, 0.1);
    margin: 0 16px;
  }
}
