@import '~src/css/quasar.variables.scss', 'quasar/src/css/variables.sass';

.drag-enter {
  border: 1px dashed white;
}
.drag-start {
  opacity: 0;
}

.desktop-box {
  .desktop_app_box {
    width: 60px;
    height: 100%;
    display: flex;
    align-items: center;
    position: absolute;
    top: 0px;
    left: 24px;
    z-index: 999;
    .desktop_app {
      width: 100%;
      max-height: 94%;
      border: 1px solid rgba(255, 255, 255, 0.2);
      border-radius: 16px;
      padding-top: 20px;
      padding-bottom: 20px;

      background: rgba(246, 246, 246, 0.3);
      border: 1px solid rgba(255, 255, 255, 0.2);
      filter: drop-shadow(0px 0px 40px rgba(0, 0, 0, 0.2))
        drop-shadow(0px 0px 2px rgba(0, 0, 0, 0.4));
      backdrop-filter: blur(120px);
      display: flex;
      flex-direction: column;

      .desktop_avatar_border {
        width: 36px;
        height: 0px;
        opacity: 0.3;
        border-bottom: 1px solid rgba(31, 24, 20, 1);
      }
      .desktop_user_avatar {
        display: flex;
        flex-wrap: wrap;
        justify-content: center;
        .desktop_avatar {
          width: 36px;
          height: 36px;
          box-shadow: 0px 0px 11px 0px rgba(0, 0, 0, 0.2);
          border-radius: 50%;
          margin-bottom: 12px;
          cursor: pointer;
          overflow: hidden;
        }
        .dock_icon {
          margin-top: 14px;
          width: 32px;
          height: 32px;
          border-radius: 16px;
          overflow: hidden;
          display: flex;
          flex-wrap: wrap;
          justify-content: center;
          border-radius: 18px;
          background: rgba(255, 255, 255, 0.2);
          display: flex;
          align-items: center;
          justify-content: center;
          justify-content: center;
          cursor: pointer;
          img {
            width: 16px;
            height: 16px;
          }
        }
        .desktop_search {
          margin-top: 14px;
          width: 100%;
          width: 32px;
          height: 32px;
          display: flex;
          flex-wrap: wrap;
          justify-content: center;
          img {
            cursor: pointer;
          }
        }
        .desktop_notify {
          margin-top: 14px;
          width: 100%;
          display: flex;
          flex-wrap: wrap;
          justify-content: center;
          img {
            cursor: pointer;
          }
        }
        .desktop_logout {
          margin-top: 14px;
          width: 100%;
          display: flex;
          flex-wrap: wrap;
          justify-content: center;
          .desktop_message_icons {
            right: -17px;
          }
          img {
            cursor: pointer;
          }
        }
      }
      .column_apps_all {
        width: 100%;
        flex: 1;
        // min-height: 200px;
        // max-height: 555px;
        // overflow: hidden;
        position: relative;
        img {
          cursor: pointer;
        }
        .img_parent {
          display: flex;
          &::after {
            content: '';
            display: block;
            width: 4px;
            height: 4px;
            background: rgba(255, 255, 255, 0.8);
            border-radius: 50%;
            margin-right: 6px;
          }
        }
        .menu_open {
          background: $background-1;
          // backdrop-filter: blur(120px);
          border-radius: 6px;
          padding: 4px;
          opacity: 0;
          animation: fadeIn 0.5s forwards;
          .context_triangle {
            position: absolute;
            top: 10px;
            left: -8px;
            width: 0;
            height: 0;
            border-top: 8px solid transparent;
            border-bottom: 8px solid transparent;
            border-right: 8px solid $background-1;
          }
          .item {
            font-size: 12px;
            line-height: 16px;
            font-family: Roboto-Regular, Roboto;
            font-weight: 400;
            color: $ink-1;
            text-align: left;
            margin: 0px;
            cursor: pointer;
            white-space: nowrap;
            padding: 4px 8px;
            border-radius: 4px;
            &:hover {
              background-color: rgba(0, 0, 0, 0.1);
            }

            &.red_font {
              color: $negative;
            }
          }
        }

        @keyframes fadeIn {
          to {
            opacity: 1;
          }
        }
        .menu_hide {
          display: none;
          opacity: 1;
          animation: fadeOut 0.5s forwards;
        }

        @keyframes fadeOut {
          to {
            opacity: 0;
          }
        }

        .column_myapps {
          width: 100%;
          display: flex;
          flex-wrap: wrap;
          justify-content: center;
          padding-top: 15px;
          cursor: pointer;
          .column_myapps_logo {
            width: 40px;
            height: 40px;
            overflow: hidden;
            box-shadow: 0px 2px 10px 0px rgba(0, 0, 0, 0.2);
            border-radius: 5px;
            margin-bottom: 16px;
            background-position: center;
            background-repeat: no-repeat;
            background-size: contain;
          }
        }
      }
    }
  }
}
